{"parameters":"z.object({material:z.string().default("oak_planks").describe("The block type to use for construction, e.g., oak_planks."),wallHeight:z.number().int().min(1).max(3).default(2).describe("Total height of the walls in blocks."),includeRoof:z.boolean().default(true).describe("Whether to place a ceiling block above the bot."),addDoor:z.boolean().default(false).describe("Whether to try using a door from inventory instead of a wall block at the front.")})","executionArgs":{"material":"oak_planks","wallHeight":2,"includeRoof":true,"addDoor":true},"code":"const normalize = (n) => String(n).trim().toLowerCase().replace(/^minecraft:/, '').replace(/\\s+/g, '_');
const requestedMaterial = normalize(args.material);
if (!bot.entity || bot.health <= 0) {
  return '<UNSAFE>: Bot is not alive.';
}
const blocks = bot.inventory.items().filter(item => normalize(item.name).includes(requestedMaterial) || normalize(item.displayName).includes(requestedMaterial));
const totalBlocks = blocks.reduce((acc, item) => acc + item.count, 0);
const doorItem = args.addDoor ? bot.inventory.items().find(item => normalize(item.name).includes('door')) : null;
const needed = 4 * args.wallHeight + (args.includeRoof ? 1 : 0);
if (totalBlocks < (args.addDoor && doorItem ? needed - 2 : needed)) {
  return `<NO ITEM>: Not enough ${args.material} (needed ${needed}, have ${totalBlocks})`;
}
startBackgroundSkill(bot, 'emergency_box', async function (token) {
  const center = bot.entity.position.floored();
  const pollMs = 50;
  const wallOffsets = [new Vec3(1, 0, 0), new Vec3(-1, 0, 0), new Vec3(0, 0, 1), new Vec3(0, 0, -1)];
  const targets = [];
  for (let h = 0; h < args.wallHeight; h++) {
    for (let i = 0; i < wallOffsets.length; i++) {
      if (args.addDoor && doorItem && i === 0 && h < 2) continue;
      targets.push(center.plus(wallOffsets[i]).offset(0, h, 0));
    }
  }
  if (args.includeRoof) {
    targets.push(center.offset(0, args.wallHeight, 0));
  }
  try {
    if (!await waitUntilWorldActive(bot, token)) return;
    const movements = new Movements(bot);
    bot.pathfinder.setMovements(movements);
    bot.pathfinder.setGoal(new goals.GoalBlock(center.x, center.y, center.z));
    await waitForActiveMs(bot, token, 400, pollMs);
    for (const pos of targets) {
      if (!canContinueBotAction(bot, token)) return;
      const blockAtPos = bot.blockAt(pos);
      if (blockAtPos && blockAtPos.name !== 'air' && blockAtPos.name !== 'water' && blockAtPos.name !== 'lava' && blockAtPos.name !== 'grass') continue;
      const neighbors = [new Vec3(0, -1, 0), new Vec3(1, 0, 0), new Vec3(-1, 0, 0), new Vec3(0, 0, 1), new Vec3(0, 0, -1), new Vec3(0, 1, 0)];
      let ref = null;
      let face = null;
      for (const off of neighbors) {
        const nPos = pos.plus(off);
        const nb = bot.blockAt(nPos);
        if (nb && nb.name !== 'air' && nb.name !== 'water' && nb.name !== 'lava') {
          ref = nb;
          face = off.scaled(-1);
          break;
        }
      }
      if (!ref) continue;
      const currentItem = bot.inventory.items().find(item => normalize(item.name).includes(requestedMaterial) || normalize(item.displayName).includes(requestedMaterial));
      if (!currentItem) break;
      await bot.equip(currentItem, 'hand');
      await bot.lookAt(ref.position.offset(0.5, 0.5, 0.5), true);
      if (!await waitUntilWorldActive(bot, token)) return;
      try {
        await bot.placeBlock(ref, face);
      } catch (e) {}
      await waitForActiveMs(bot, token, 100, pollMs);
    }
    if (args.addDoor && doorItem && canContinueBotAction(bot, token)) {
      const doorPos = center.plus(wallOffsets[0]);
      const ref = bot.blockAt(doorPos.offset(0, -1, 0));
      if (ref && ref.name !== 'air') {
        await bot.equip(doorItem, 'hand');
        await bot.lookAt(ref.position.offset(0.5, 0.5, 0.5), true);
        try {
          await bot.placeBlock(ref, new Vec3(0, 1, 0));
        } catch (e) {}
      }
    }
  } finally {
    bot.pathfinder.stop();
  }
});
return `<STARTED>: Building a ${args.wallHeight}-high box using ${args.material} at ${bot.entity.position.floored()}.`;"}

{"parameters":"z.object({targetEntityId:z.union([z.number().int(),z.string().min(1)]).optional().describe("The hostile entity to kite. If omitted, the bot will target the nearest hostile."),preferredDistance:z.number().min(5).max(25).default(12).describe("The ideal distance to maintain when shooting."),retreatThreshold:z.number().min(3).max(20).default(8).describe("Distance that triggers a retreat if the hostile gets too close."),maxShots:z.number().int().min(1).max(20).default(5).describe("Stop after firing this many shots."),maxDurationMs:z.number().int().min(1000).max(60000).default(20000).describe("Stop kiting after this duration.")})","executionArgs":{"preferredDistance":12,"retreatThreshold":8,"maxShots":5,"maxDurationMs":20000},"code":"const pollMs = 100;
const drawMs = 1000;
const cooldownMs = 400;
const hostileNames = new Set(['zombie','skeleton','husk','drowned','stray','spider','creeper','baby_zombie','piglin','pillager','vex','vindicator']);
const arrowNames = new Set(['arrow','spectral_arrow','tipped_arrow']);
const getArrowCount = function() {
  return bot.inventory.items().filter(item => arrowNames.has(item.name)).reduce((sum, item) => sum + item.count, 0);
};
const findTarget = function() {
  if (args.targetEntityId) {
    const id = String(args.targetEntityId);
    return Object.values(bot.entities).find(e => e && e.isValid && String(e.id) === id);
  }
  return bot.nearestEntity(e => {
    if (!e || !e.isValid || e.type !== 'hostile' && !hostileNames.has(e.name || '')) return false;
    return e.position.distanceTo(bot.entity.position) < 32;
  });
};
if (!bot.entity || bot.health <= 0) return '<UNSAFE>: Bot is not alive.';
const bow = bot.inventory.items().find(i => i.name === 'bow');
if (!bow) return '<NO ITEM>: Missing bow.';
if (getArrowCount() <= 0) return '<NO ITEM>: Missing arrows.';
const initialTarget = findTarget();
if (!initialTarget) return '<NO TARGET>: No hostiles nearby to kite.';
startBackgroundSkill(bot, 'kite_and_shoot', async function(token) {
  const movements = new Movements(bot);
  movements.canDig = false;
  bot.pathfinder.setMovements(movements);
  let shotsFired = 0;
  const startTime = Date.now();
  try {
    while (canContinueBotAction(bot, token)) {
      if (Date.now() - startTime > args.maxDurationMs) break;
      if (shotsFired >= args.maxShots) break;
      if (getArrowCount() <= 0) break;
      const target = findTarget();
      if (!target) break;
      const dist = bot.entity.position.distanceTo(target.position);
      if (dist < args.retreatThreshold) {
        const diff = bot.entity.position.minus(target.position).normalize().scale(args.retreatThreshold + 4);
        const retreatPos = target.position.plus(diff);
        bot.pathfinder.setGoal(new goals.GoalNear(retreatPos.x, retreatPos.y, retreatPos.z, 1));
        if (!await waitForActiveMs(bot, token, pollMs * 5)) break;
      } else if (dist > args.preferredDistance + 4) {
        bot.pathfinder.setGoal(new goals.GoalFollow(target, args.preferredDistance));
        if (!await waitForActiveMs(bot, token, pollMs * 5)) break;
      } else {
        bot.pathfinder.setGoal(null);
        if (!await waitUntilWorldActive(bot, token)) break;
        await bot.lookAt(target.position.offset(0, (target.height || 1.8) * 0.8, 0), true);
        if (!await waitUntilWorldActive(bot, token)) break;
        await bot.equip(bow, 'hand');
        bot.activateItem();
        if (!await waitForActiveMs(bot, token, drawMs)) {
          bot.deactivateItem();
          break;
        }
        bot.deactivateItem();
        shotsFired++;
        if (!await waitForActiveMs(bot, token, cooldownMs)) break;
      }
      if (!await waitUntilWorldActive(bot, token)) break;
    }
  } finally {
    bot.pathfinder.setGoal(null);
    bot.deactivateItem();
  }
});
return '<STARTED>: Kiting and shooting hostiles within ' + args.preferredDistance + ' blocks. Status based on current vicinity.';"}
